Binary Search Function<pre><code>bool binarySearch(int arr[], int n, int target) {
    int left = 0, right = n - 1;

    while (left &lt;= right) {
        int mid = left + (right - left) / 2;

        if (arr[mid] == target) {
            return true;
        }

        if (arr[mid] &lt; target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return false;
}
</code></pre> Bubble Sort Function<pre><code>void bubbleSort(int arr[], int n) {
    for (int i = 0; i &lt; n - 1; i++) {
        for (int j = 0; j &lt; n - i - 1; j++) {
            if (arr[j] &gt; arr[j + 1]) {
                // Swap elements
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}
</code></pre>

Utility Functions<pre><code>// Fungsi untuk menukar dua nilai
void swap(int&amp; a, int&amp; b) {
    int temp = a;
    a = b;
    b = temp;
}

// Fungsi untuk cek bilangan prima
bool isPrime(int n) {
    if (n &lt;= 1) return false;
    if (n &lt;= 3) return true;
    if (n % 2 == 0 || n % 3 == 0) return false;

    for (int i = 5; i * i &lt;= n; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) {
            return false;
        }
    }
    return true;
}

// Fungsi untuk menghitung faktorial
long long factorial(int n) {
    if (n &lt;= 1) return 1;

    long long result = 1;
    for (int i = 2; i &lt;= n; i++) {
        result *= i;
    }
    return result;
}
</code></pre>

