Validasi Email Sederhana<pre><code>bool isValidEmail(string email) {
    size_t at_pos = email.find('@');
    size_t dot_pos = email.rfind('.');

    return (at_pos != string::npos &amp;&amp; 
            dot_pos != string::npos &amp;&amp; 
            at_pos &lt; dot_pos &amp;&amp;
            at_pos &gt; 0 &amp;&amp;
            dot_pos &lt; email.length() - 1);
}

int main() {
    string email;
    cout &lt;&lt; "Masukkan email: ";
    cin &gt;&gt; email;

    if (isValidEmail(email)) {
        cout &lt;&lt; "Email valid" &lt;&lt; endl;
    } else {
        cout &lt;&lt; "Email tidak valid" &lt;&lt; endl;
    }

    return 0;
}
</code></pre>

Menghitung Kata<pre><code>int countWords(string sentence) {
    if (sentence.empty()) return 0;

    int count = 0;
    bool inWord = false;

    for (char c : sentence) {
        if (c != ' ' &amp;&amp; !inWord) {
            inWord = true;
            count++;
        } else if (c == ' ') {
            inWord = false;
        }
    }

    return count;
}

int main() {
    string text = "Hello world programming";
    cout &lt;&lt; "Jumlah kata: " &lt;&lt; countWords(text) &lt;&lt; endl;  // Output: 3
    return 0;
}
</code></pre>

Cek Palindrome<pre><code>bool isPalindrome(string str) {
    // Convert to lowercase dan hapus spasi
    string clean = "";
    for (char c : str) {
        if (c != ' ') {
            clean += tolower(c);
        }
    }

    int left = 0;
    int right = clean.length() - 1;

    while (left &lt; right) {
        if (clean[left] != clean[right]) {
            return false;
        }
        left++;
        right--;
    }

    return true;
}

int main() {
    string word = "A man a plan a canal Panama";
    cout &lt;&lt; word &lt;&lt; " is palindrome: " &lt;&lt; isPalindrome(word) &lt;&lt; endl;
    return 0;
}
</code></pre>

Memisahkan String<pre><code>vector&lt;string&gt; split(string str, char delimiter) {
    vector&lt;string&gt; tokens;
    string token = "";

    for (char c : str) {
        if (c == delimiter) {
            if (!token.empty()) {
                tokens.push_back(token);
                token = "";
            }
        } else {
            token += c;
        }
    }

    if (!token.empty()) {
        tokens.push_back(token);
    }

    return tokens;
}

int main() {
    string data = "apple,banana,orange,grape";
    vector&lt;string&gt; fruits = split(data, ',');

    for (string fruit : fruits) {
        cout &lt;&lt; fruit &lt;&lt; endl;
    }

    return 0;
}
</code></pre>

Useful String Algorithms<pre><code>#include &lt;algorithm&gt;
#include &lt;string&gt;

int main() {
    string text = "Programming";

    // Reverse string
    reverse(text.begin(), text.end());
    cout &lt;&lt; text &lt;&lt; endl;  // gnimmargorP

    // Sort karakter dalam string
    string word = "hello";
    sort(word.begin(), word.end());
    cout &lt;&lt; word &lt;&lt; endl;  // ehllo

    // Remove duplicates
    string dup = "programming";
    sort(dup.begin(), dup.end());
    dup.erase(unique(dup.begin(), dup.end()), dup.end());
    cout &lt;&lt; dup &lt;&lt; endl;  // agimnopr

    // Transform to uppercase
    string lower = "hello world";
    transform(lower.begin(), lower.end(), lower.begin(), ::toupper);
    cout &lt;&lt; lower &lt;&lt; endl;  // HELLO WORLD

    return 0;
}
</code></pre>
